<template>
    <view class="contain">
        <view class="chatContent">
            <view class="msgItem" v-for="(item,index) in messageArr" @click="jumpUrl('https://www.baidu.com')">
                <view class="msgDate" v-if="item.Showdate" v-text="`${item.Showdate}  (${item.week})`"></view>
                <view class="userItem" :style="item.sender == 1? 'flex-direction: row-reverse' : '' ">
                    <view>
                        <view class="avatar">
                            <image :src="item.avatar || defaultImage" mode=""></image>
                        </view>
                        <view class="chatName" v-text="item.name"></view>
                    </view>
                    <view class="detail" :style="item.sender == 1? 'flex-direction: row-reverse' : '' ">
                        <view v-if="item.type == 1" class="msgDetail"
                            :style="item.sender == 1? 'background:#87FA7D' : '' " v-html="item.message">
                        </view>
                        <view v-if="item.type == 2" class="msgDetailImage">
                            <image @click="previewImage(item.message)" :src="item.message" mode="aspectFill"></image>
                        </view>
                        <view class="sendTime" v-text="item.time"></view>
                    </view>
                </view>
            </view>
            <view class="blank"></view>
        </view>
        <view class="sendBox">
            <view class="boxLeft">
                <image src="../../../static/icons/fileIcon.png" mode=""></image>
                <image src="../../../static/icons/photoIcon.png" mode="" @click="chooseCamear"></image>
                <image src="../../../static/icons/imgIcon.png" mode="" @click="chooseImage"></image>
            </view>
            <view class="boxRight">
                <u-input placeholder="Aa" v-model="sendMessage" shape="circle" @confirm="send"></u-input>
            </view>
        </view>
        <peiconfirm :dates="date" :number="number" v-if="shows"></peiconfirm>
    </view>
</template>

<script>
    const admin = uni.getStorageSync("admin")
    import {
        getMessageList,
        sendMessage,
        hasRead
    } from "@/api/index.js"
    export default {
        data() {
            return {
                messageArr: [],
                query: {},
                currentMessages: [],
                fArray: [],
                defaultImage: "../../../static/images/avatar.png",
                sendMessage: "",
                history: [],
                reachBottom: true
            }
        },
        computed: {
            newMessage() {
                return this.$store.state.newMessage;
            },
        },
        created() {
            
        },
        onLoad(options) {
            let that = this
            let query = options
            that.query = query
            that.getHistory()
        },
        onPullDownRefresh() {
            this.loadMore()
        },
        onReachBottom(e) {
            let that = this
            setTimeout(function() {
                that.reachBottom = true
            }, 300)

        },
        onPageScroll(e) {
            this.reachBottom = false
        },
        watch: {
            newMessage: {
                handler(nval, oval) {
                    let that = this
                    if (nval.type == "message" && nval.data[0].uid == that.query.uid) {
                        that.currentMessages = [...that.currentMessages, ...nval.data]
                        let currentMessages = that.currentMessages
                        that.messageArr = [...that.history, ...currentMessages]
                        for (let i = 0; i < that.messageArr.length; i++) {
                            if (i > 0) {
                                if (that.messageArr[i].date == that.messageArr[i - 1].date) {
                                    that.messageArr[i].Showdate = ''
                                } else {
                                    that.messageArr[i].Showdate = that.messageArr[i].date
                                }
                            } else {
                                that.messageArr[i].Showdate = that.messageArr[i].date
                            }
                            if (that.messageArr[i].sender == 1) {
                                that.messageArr[i].name = admin.name
                            }
                        }
                        if (that.reachBottom == true) {
                            that.scollBottom()
                        }
                        let hasReadData = {}
                        hasRead.uid = that.query.uid
                        hasRead(hasReadData).then((res) => {})
                    }
                },
                deep: true, // 深度监听
                immediate: true, //立即执行
            }
        },
        methods: {
            getHistory() {
                let that = this
                let data = {}
                data.type = "detail"
                data.timestamp = that.formatTime()
                data.uid = that.query.uid
                data.mid = 0
                getMessageList(data).then((res) => {
                    if (res.code == 200) {
                        console.log("history",res)
                        that.history = res.data.messages.data.reverse()
                        let currentMessages = that.currentMessages
                        that.messageArr = [...that.history, ...currentMessages]
                        for (let i = 0; i < that.messageArr.length; i++) {
                            if (i > 0) {
                                if (that.messageArr[i].date == that.messageArr[i - 1].date) {
                                    that.messageArr[i].Showdate = ''
                                } else {
                                    that.messageArr[i].Showdate = that.messageArr[i].date
                                }
                            } else {
                                that.messageArr[i].Showdate = that.messageArr[i].date
                            }

                            if (that.messageArr[i].sender == 1) {
                                that.messageArr[i].name = admin.name
                            }
                        }
                        that.scollBottom()
                        let hasReadData = {}
                        hasReadData.uid = that.query.uid
                        hasRead(hasReadData).then((res) => {})
                    }
                })
            },
            jumpUrl(e) {
                if (e == "") {

                } else {
                    uni.navigateTo({
                        url: "../../webview/webview?link=" + e
                    })
                }

            },
            onBackPress() {
                let pages = getCurrentPages();
                let currPage = pages[pages.length - 1]
                let prePage = pages[pages.length - 2]
                if (prePage.route == "pages/message/message") {
                    prePage.$vm.getList()
                }
            },
            loadMore() {
                let that = this
                let data = {}
                data.type = "detail"
                data.timestamp = that.formatTime()
                data.uid = that.query.uid
                data.mid = that.history[0].id
                getMessageList(data).then((res) => {
                    if (res.code == 200) {
                        if (res.data.messages.data.length > 0) {
                            that.history = [...that.history,...res.data.messages.data.reverse()]
                            that.messageArr = [...that.history, ...that.messageArr]
                            for (let i = 0; i < that.messageArr.length; i++) {
                                if (i > 0) {
                                    if (that.messageArr[i].date == that.messageArr[i - 1].date) {
                                        that.messageArr[i].Showdate = ''
                                    } else {
                                        that.messageArr[i].Showdate = that.messageArr[i].date
                                    }
                                } else {
                                    that.messageArr[i].Showdate = that.messageArr[i].date
                                }

                                if (that.messageArr[i].sender == 1) {
                                    that.messageArr[i].name = admin.name
                                }
                            }

                        }
                        uni.stopPullDownRefresh()
                    }
                })
            },
            previewImage(e) {
                let that = this
                let tem = []
                tem.push(e)
                uni.previewImage({
                    current: 0,
                    urls: tem
                })
            },
            formatTime() {
                var date = new Date()
                var timeStamp = Date.parse(date)
                return timeStamp
            },
            chooseImage() {
                let that = this
                uni.chooseImage({
                    count: 1,
                    sourceType: ['album'],
                    success: (res) => {
                        const tempPaths = res.tempFilePaths
                        uni.uploadFile({
                            url: that.$baseUrl+'/tool/upload/file',
                            filePath: res.tempFilePaths[0],
                            name:"file",
                            success: (result) => {
                                if (result.errMsg == "uploadFile:ok") {
                                    let re = JSON.parse(result.data)
                                    if (re.code == 200) {
                                        let data = {}
                                        data.uid = that.query.uid
                                        data.type = 2
                                        data.message = re.data.path
                                        sendMessage(data).then((res) => {})
                                    }else if(res.code == 4003){
                                        
                                    }
                                }
                            }
                        })
                    }
                });
            },
            chooseCamear() {
                let that = this
                uni.chooseImage({
                    count: 1,
                    sourceType: ['camera'],
                    success: (res) => {
                        const tempPaths = res.tempFilePaths
                        console.log(tempPaths[0])
                        uni.uploadFile({
                            url: that.$baseUrl+'/tool/upload/file',
                            filePath: res.tempFilePaths[0],
                            name:"file",
                            success: (result) => {
                                if (result.errMsg == "uploadFile:ok") {
                                    let re = JSON.parse(result.data)
                                    if (re.code == 200) {
                                        let data = {}
                                        data.uid = that.query.uid
                                        data.type = 2
                                        data.message = re.data.path
                                        sendMessage(data).then((res) => {})
                                    }
                                }
                            }
                        })
                    }
                });
            },
            scollBottom() {
                this.$nextTick(function() {
                    setTimeout(() => {
                        uni.createSelectorQuery().select('.chatContent').boundingClientRect((res) => {
                            uni.pageScrollTo({
                                scrollTop: res.height,
                                duration: 200
                            })
                        }).exec()
                    }, 50)

                });
            },
            send() {
                let that = this
                let data = {}
                that.reachBottom = true
                data.uid = that.query.uid
                data.type = 1
                data.message = that.sendMessage
                if (that.sendMessage == '') {
                    uni.showToast({
                        title: "请输入内容",
                        icon: "none"
                    })
                } else {
                    sendMessage(data).then((res) => {
                        if (res.code == 200) {
                            that.sendMessage = ""
                        }
                    })
                }
            }
        }
    }
</script>

<style lang="scss">
    .contain {
        display: flex;
        flex-direction: column;
        height: calc(100vh - 44px);

        .msgDetailImage {
            width: 50vw;

            image {
                width: 100%;
            }
        }

        .chatContent {
            flex: 1;
            background-color: #fff;
            box-sizing: border-box;
            padding: 0 32upx;

            .userItem {
                display: flex;

                .avatar {
                    width: 60upx;
                    height: 60upx;
                    border-radius: 50%;
                    flex-shrink: 0;
                    overflow: hidden;

                    image {
                        width: 100%;
                        height: 100%;
                    }
                }

                .detail {
                    display: flex;
                    align-items: flex-end;

                    .msgDetail {
                        max-width: 492upx;
                        box-sizing: border-box;
                        padding: 20upx;
                        font-size: 32upx;
                        font-family: Hiragino Sans-W3, Hiragino Sans;
                        font-weight: normal;
                        color: #1D1D1F;
                        background: rgba(143, 168, 248, 0.2);
                        border-radius: 20upx;
                        margin: 0 8upx;
                    }

                    .sendTime {
                        font-size: 20upx;
                        font-family: Hiragino Sans-W3, Hiragino Sans;
                        font-weight: normal;
                        color: #86868B;
                    }
                }
            }
        }

        .msgItem {
            margin-bottom: 24upx;

            .msgDate {
                text-align: center;
                padding: 24upx 0;
            }
        }

        .blank {
            width: 100vw;
            height: 90upx;
        }

        .chatName {
            font-size: 24upx;
            color: #aaa
        }

        .sendBox {
            width: 100vw;
            height: 90upx;
            background: #F9F9F9;
            box-shadow: 0px -1upx 0px 2upx rgba(0, 0, 0, 0.3);
            opacity: 0.93;
            display: flex;
            align-items: center;
            box-sizing: border-box;
            padding: 0 32upx;
            flex-shrink: 0;
            position: fixed;
            bottom: 0;
            left: 0;

            .boxLeft {
                display: flex;
                align-items: center;

                image {
                    width: 54upx;
                    height: 42upx;
                    margin-right: 28upx
                }

                image:first-child {
                    width: 46upx;
                    height: 50upx
                }
            }

            .boxRight {
                flex: 1
            }
        }
    }
</style>
